  1→use agentrail_core::error::Result;
  2→use agentrail_core::{SagaStatus, StepRole, StepStatus, Trajectory};
  3→use agentrail_store::{saga, session, step, trajectory};
  4→use std::path::Path;
  5→
  6→pub struct CompleteArgs<'a> {
  7→    pub summary: Option<&'a str>,
  8→    pub next_slug: Option<&'a str>,
  9→    pub next_prompt: Option<&'a str>,
 10→    pub next_context: Vec<String>,
 11→    pub next_role: &'a str,
 12→    pub next_task_type: Option<&'a str>,
 13→    pub planned: Vec<String>,
 14→    pub done: bool,
 15→    /// Reward for this step's trajectory (-1, 0, or 1)
 16→    pub reward: Option<i8>,
 17→    /// Description of actions taken (for trajectory recording)
 18→    pub actions: Option<&'a str>,
 19→    /// Failure mode identifier (for trajectory recording on failure)
 20→    pub failure_mode: Option<&'a str>,
 21→}
 22→
 23→pub fn run(saga_path: &Path, args: &CompleteArgs<'_>) -> Result<()> {
 24→    let mut config = saga::load_saga(saga_path)?;
 25→    let saga_dir = saga::saga_dir(saga_path);
 26→
 27→    // Try to snapshot session (non-fatal, silent when no session exists)
 28→    if let Ok((path, lines)) = session::snapshot_session(&saga_dir, saga_path)
 29→        && lines > 0
 30→    {
 31→        eprintln!("Snapshotted {} new lines to {}", lines, path.display());
 32→    }
 33→
 34→    // Read summary
 35→    let summary_text = match args.summary {
 36→        Some(raw) => agentrail_core::read_input(raw)?,
 37→        None => String::new(),
 38→    };
 39→
 40→    // Complete current step (or handle step 0)
 41→    if config.current_step == 0 {
 42→        if !summary_text.is_empty() {
 43→            let summary_path = saga_dir.join("step0-summary.md");
 44→            std::fs::write(&summary_path, &summary_text)?;
 45→            println!("Saved step 0 summary.");
 46→        }
 47→    } else {
 48→        let step_dir = step::find_step_dir(&saga_dir, config.current_step)?;
 49→        let mut step_config = step::load_step(&step_dir)?;
 50→
 51→        // Auto-begin if still pending
 52→        if step_config.status == StepStatus::Pending {
 53→            step::transition_step(&mut step_config, StepStatus::InProgress)?;
 54→        }
 55→
 56→        step::transition_step(&mut step_config, StepStatus::Completed)?;
 57→        step::save_step(&step_dir, &step_config)?;
 58→
 59→        if !summary_text.is_empty() {
 60→            step::save_summary(&step_dir, &summary_text)?;
 61→        }
 62→
 63→        // Record trajectory if step has a task_type and reward is provided
 64→        if let Some(ref task_type) = step_config.task_type {
 65→            let reward = args.reward.unwrap_or(1);
 66→            let action = args
 67→                .actions
 68→                .map(|s| s.to_string())
 69→                .unwrap_or_else(|| summary_text.clone());
 70→            let result = if reward > 0 {
 71→                "success".to_string()
 72→            } else if let Some(fm) = args.failure_mode {
 73→                format!("failure: {fm}")
 74→            } else {
 75→                "failure".to_string()
 76→            };
 77→
 78→            let t = Trajectory {
 79→                task_type: task_type.clone(),
 80→                state: serde_json::json!({"step": step_config.slug, "number": step_config.number}),
 81→                action,
 82→                result,
 83→                reward,
 84→                timestamp: agentrail_core::timestamp_iso(),
 85→            };
 86→            let path = trajectory::save_trajectory(&saga_dir, &t)?;
 87→            println!(
 88→                "Recorded trajectory for '{}' (reward={:+}) at {}",
 89→                task_type,
 90→                reward,
 91→                path.display()
 92→            );
 93→        }
 94→
 95→        println!(
 96→            "Completed step {:03}-{}.",
 97→            step_config.number, step_config.slug
 98→        );
 99→    }
100→
101→    if args.done {
102→        config.status = SagaStatus::Completed;
103→        saga::save_saga(saga_path, &config)?;
104→        println!("Saga '{}' marked as complete.", config.name);
105→        return Ok(());
106→    }
107→
108→    // Advance to next step: use existing planned step if present, else create new
109→    let next_number = config.current_step + 1;
110→    if let Ok(existing_dir) = step::find_step_dir(&saga_dir, next_number) {
111→        // A planned step already exists at this number -- advance to it
112→        let existing = step::load_step(&existing_dir)?;
113→        config.current_step = next_number;
114→        saga::save_saga(saga_path, &config)?;
115→        println!(
116→            "Advanced to existing step {:03}-{} [{}].",
117→            existing.number, existing.slug, existing.role
118→        );
119→    } else if let (Some(slug), Some(prompt_raw)) = (args.next_slug, args.next_prompt) {
120→        // No planned step exists -- create a new one
121→        let prompt = agentrail_core::read_input(prompt_raw)?;
122→        let role = parse_role(args.next_role);
123→
124→        let description = agentrail_core::truncate(&prompt, 80);
125→        step::create_step(&step::CreateStepParams {
126→            saga_dir: &saga_dir,
127→            number: next_number,
128→            slug,
129→            prompt: &prompt,
130→            description: &description,
131→            role,
132→            context_files: &args.next_context,
133→            task_type: args.next_task_type,
134→            job_spec: None,
135→        })?;
136→
137→        config.current_step = next_number;
138→        saga::save_saga(saga_path, &config)?;
139→
140→        println!("Created step {:03}-{}.", next_number, slug);
141→    }
142→
143→    // Create planned steps as pending placeholders
144→    let base = config.current_step;
145→    for (i, planned) in args.planned.iter().enumerate() {
146→        let number = base + 1 + i as u32;
147→        let (slug, desc) = match planned.split_once(": ") {
148→            Some((s, d)) => (s.trim(), d.trim()),
149→            None => (planned.trim(), planned.trim()),
150→        };
151→        step::create_step(&step::CreateStepParams {
152→            saga_dir: &saga_dir,
153→            number,
154→            slug,
155→            prompt: "",
156→            description: desc,
157→            role: StepRole::Legacy,
158→            context_files: &[],
159→            task_type: None,
160→            job_spec: None,
161→        })?;
162→        println!("Planned step {:03}-{}.", number, slug);
163→    }
164→
165→    println!();
166→    println!("=== SESSION COMPLETE ===");
167→    println!("STOP. Do not make further changes in this session.");
168→    println!("Any work after this point will be untracked.");
169→    println!("Start a new session and run `agentrail next` for the next step.");
170→
171→    Ok(())
172→}
173→
174→fn parse_role(s: &str) -> StepRole {
175→    match s {
176→        "meta" => StepRole::Meta,
177→        "production" => StepRole::Production,
178→        "deterministic" => StepRole::Deterministic,
179→        "validation" => StepRole::Validation,
180→        _ => StepRole::Legacy,
181→    }
182→}
