 6→/// Add a new step to the saga without completing the current one.
 7→/// Used for maintenance mode and ad-hoc task addition.
 8→pub fn run(
 9→    saga_path: &Path,
10→    slug: &str,
11→    prompt_raw: &str,
12→    role: &str,
13→    task_type: Option<&str>,
14→) -> Result<()> {
15→    let config = saga::load_saga(saga_path)?;
16→    let saga_dir = saga::saga_dir(saga_path);
17→
18→    let prompt = agentrail_core::read_input(prompt_raw)?;
19→
20→    // Find the highest existing step number
21→    let steps = step::list_steps(&saga_dir)?;
22→    let max_number = steps.iter().map(|(_, s)| s.number).max().unwrap_or(0);
23→    let new_number = max_number.max(config.current_step) + 1;
24→
25→    let role = match role {
26→        "meta" => StepRole::Meta,
27→        "production" => StepRole::Production,
28→        "deterministic" => StepRole::Deterministic,
29→        "validation" => StepRole::Validation,
30→        _ => StepRole::Production,
31→    };
32→
33→    let description = agentrail_core::truncate(&prompt, 80);
34→    step::create_step(&step::CreateStepParams {
35→        saga_dir: &saga_dir,
36→        number: new_number,
37→        slug,
38→        prompt: &prompt,
39→        description: &description,
40→        role,
41→        context_files: &[],
42→        task_type,
43→        job_spec: None,
44→    })?;
45→
46→    // If saga has no current step or current step is complete, advance
47→    if config.current_step == 0 || config.current_step < new_number {
48→        if let Ok(current_dir) = step::find_step_dir(&saga_dir, config.current_step) {
49→            let current = step::load_step(&current_dir)?;
50→            if current.status == agentrail_core::StepStatus::Completed
51→                || current.status == agentrail_core::StepStatus::Blocked
52→            {
53→                let mut config = config;
54→                config.current_step = new_number;
55→                config.status = agentrail_core::SagaStatus::Active;
56→                saga::save_saga(saga_path, &config)?;
57→                println!("Advanced to step {:03}-{}.", new_number, slug);
58→                return Ok(());
59→            }
60→        } else if config.current_step == 0 {
61→            let mut config = config;
62→            config.current_step = new_number;
63→            saga::save_saga(saga_path, &config)?;
64→            println!("Advanced to step {:03}-{}.", new_number, slug);
65→            return Ok(());
66→        }
67→    }
68→
69→    println!("Added step {:03}-{}.", new_number, slug);
70→    Ok(())
71→}
