 15→/// Find a step directory by number (slug may vary).
 16→pub fn find_step_dir(saga_dir: &Path, number: u32) -> Result<PathBuf> {
 17→    let steps_dir = saga_dir.join("steps");
 18→    if !steps_dir.is_dir() {
 19→        return Err(Error::NoSteps);
 20→    }
 21→    let prefix = format!("{:03}-", number);
 22→    for entry in std::fs::read_dir(&steps_dir)? {
 23→        let entry = entry?;
 24→        if let Some(name) = entry.file_name().to_str()
 25→            && name.starts_with(&prefix)
 26→        {
 27→            return Ok(entry.path());
 28→        }
 29→    }
 30→    Err(Error::NoCurrentStep)
 31→}
