 46→pub struct CreateStepParams<'a> {
 47→    pub saga_dir: &'a Path,
 48→    pub number: u32,
 49→    pub slug: &'a str,
 50→    pub prompt: &'a str,
 51→    pub description: &'a str,
 52→    pub role: StepRole,
 53→    pub context_files: &'a [String],
 54→    pub task_type: Option<&'a str>,
 55→    pub job_spec: Option<agentrail_core::JobSpec>,
 56→}
