 58→pub fn create_step(p: &CreateStepParams<'_>) -> Result<PathBuf> {
 59→    let saga_dir = p.saga_dir;
 60→    let number = p.number;
 61→    let slug = p.slug;
 62→    let prompt = p.prompt;
 63→    let description = p.description;
 64→    let role = p.role.clone();
 65→    let context_files = p.context_files;
 66→    let task_type = p.task_type;
 67→    let dir = step_dir(saga_dir, number, slug);
 68→    std::fs::create_dir_all(&dir)?;
 69→
 70→    let config = StepConfig {
 71→        number,
 72→        slug: slug.to_string(),
 73→        status: StepStatus::Pending,
 74→        description: description.to_string(),
 75→        role,
 76→        context_files: context_files.to_vec(),
 77→        created_at: agentrail_core::timestamp_iso(),
 78→        completed_at: None,
 79→        transcript_file: None,
 80→        job_spec: p.job_spec.clone(),
 81→        packet_file: None,
 82→        task_type: task_type.map(|s| s.to_string()),
 83→    };
 84→
 85→    save_step(&dir, &config)?;
 86→    std::fs::write(dir.join("prompt.md"), prompt)?;
 87→
 88→    Ok(dir)
 89→}
