 91→pub fn transition_step(config: &mut StepConfig, to: StepStatus) -> Result<()> {
 92→    let valid = matches!(
 93→        (&config.status, &to),
 94→        (StepStatus::Pending, StepStatus::InProgress)
 95→            | (StepStatus::InProgress, StepStatus::Completed)
 96→            | (StepStatus::InProgress, StepStatus::Blocked)
 97→    );
 98→
 99→    if !valid {
100→        return Err(Error::InvalidStepTransition {
101→            from: config.status.to_string(),
102→            to: to.to_string(),
103→        });
104→    }
105→
106→    if to == StepStatus::Completed {
107→        config.completed_at = Some(agentrail_core::timestamp_iso());
108→    }
109→
110→    config.status = to;
111→    Ok(())
112→}
