114→/// List all steps sorted by number.
115→pub fn list_steps(saga_dir: &Path) -> Result<Vec<(PathBuf, StepConfig)>> {
116→    let steps_dir = saga_dir.join("steps");
117→    if !steps_dir.is_dir() {
118→        return Ok(vec![]);
119→    }
120→
121→    let mut steps = Vec::new();
122→    for entry in std::fs::read_dir(&steps_dir)? {
123→        let entry = entry?;
124→        if entry.file_type()?.is_dir() {
125→            let step_toml = entry.path().join("step.toml");
126→            if step_toml.is_file() {
127→                let config = load_step(&entry.path())?;
128→                steps.push((entry.path(), config));
129→            }
130→        }
131→    }
132→
133→    steps.sort_by_key(|(_, c)| c.number);
134→    Ok(steps)
135→}
