  1→//! cor24-dbg: GDB-like CLI debugger for the MakerLisp COR24 processor
  2→//!
  3→//! Usage:
  4→//!   cor24-dbg <file.lgo>           Load an LGO file and start debugging
  5→//!   cor24-dbg --entry 0x93 <file>  Set entry point address
  6→
  7→use cor24_emulator::emulator::{EmulatorCore, StopReason};
  8→use std::io::{self, BufRead, Write};
  9→
 10→fn main() {
 11→    let args: Vec<String> = std::env::args().collect();
 12→    if args.len() < 2 {
 13→        eprintln!("cor24-dbg: MakerLisp COR24 debugger\n");
 14→        eprintln!("Usage:");
 15→        eprintln!("  cor24-dbg <file.lgo>                Load LGO file");
 16→        eprintln!("  cor24-dbg --entry <addr> <file.lgo>  Set entry point");
 17→        eprintln!("\nCommands: run, step, break, info, examine, disas, reset, quit");
 18→        std::process::exit(1);
 19→    }
 20→
 21→    let mut entry_override: Option<u32> = None;
 22→    let mut filename = None;
 23→
 24→    let mut i = 1;
 25→    while i < args.len() {
 26→        match args[i].as_str() {
 27→            "--entry" | "-e" => {
 28→                i += 1;
 29→                if i < args.len() {
 30→                    entry_override = Some(parse_addr(&args[i]).unwrap_or_else(|| {
 31→                        eprintln!("Bad address: {}", args[i]);
 32→                        std::process::exit(1);
 33→                    }));
 34→                }
 35→            }
 36→            _ => {
 37→                filename = Some(args[i].clone());
 38→            }
 39→        }
 40→        i += 1;
 41→    }
 42→
 43→    let filename = filename.unwrap_or_else(|| {
 44→        eprintln!("No file specified");
 45→        std::process::exit(1);
 46→    });
 47→
 48→    let mut dbg = Debugger::new();
 49→
 50→    if let Err(e) = dbg.load_file(&filename, entry_override) {
 51→        eprintln!("Error loading {}: {}", filename, e);
 52→        std::process::exit(1);
 53→    }
 54→
 55→    dbg.repl();
 56→}
 57→
 58→struct Debugger {
 59→    emu: EmulatorCore,
 60→    loaded: bool,
 61→    /// Track UART output position for incremental printing
 62→    uart_printed: usize,
 63→}
 64→
 65→impl Debugger {
 66→    fn new() -> Self {
 67→        Self {
 68→            emu: EmulatorCore::new(),
 69→            loaded: false,
 70→            uart_printed: 0,
 71→        }
 72→    }
 73→
 74→    fn load_file(&mut self, path: &str, entry: Option<u32>) -> Result<(), String> {
 75→        let content =
 76→            std::fs::read_to_string(path).map_err(|e| format!("Cannot read file: {}", e))?;
 77→
 78→        let bytes = self.emu.load_lgo(&content, entry)?;
 79→        self.loaded = true;
 80→        self.uart_printed = 0;
 81→
 82→        println!("Loaded {} bytes from {}", bytes, path);
 83→        println!("PC = 0x{:06X}", self.emu.pc());
 84→        Ok(())
 85→    }
 86→
 87→    fn repl(&mut self) {
 88→        let stdin = io::stdin();
 89→        let mut last_cmd = String::new();
 90→
 91→        loop {
 92→            print!("(cor24) ");
 93→            io::stdout().flush().ok();
 94→
 95→            let mut line = String::new();
 96→            if stdin.lock().read_line(&mut line).unwrap_or(0) == 0 {
 97→                println!();
 98→                break;
 99→            }
100→            let line = line.trim().to_string();
101→
102→            let cmd = if line.is_empty() {
103→                last_cmd.clone()
104→            } else {
105→                last_cmd = line.clone();
106→                line
107→            };
108→
109→            if cmd.is_empty() {
110→                continue;
111→            }
112→
113→            let parts: Vec<&str> = cmd.splitn(2, ' ').collect();
114→            let arg = if parts.len() > 1 { parts[1].trim() } else { "" };
115→
116→            match parts[0] {
117→                "q" | "quit" | "exit" => break,
118→                "r" | "run" => self.cmd_run(arg),
119→                "s" | "step" | "si" => self.cmd_step(arg),
120→                "n" | "next" => self.cmd_next(),
121→                "c" | "cont" | "continue" => self.cmd_continue(),
122→                "b" | "break" => self.cmd_break(arg),
123→                "d" | "delete" => self.cmd_delete(arg),
124→                "i" | "info" => self.cmd_info(arg),
125→                "x" | "examine" => self.cmd_examine(arg),
126→                "p" | "print" => self.cmd_print(arg),
127→                "disas" | "disassemble" => self.cmd_disas(arg),
128→                "load" => {
129→                    if arg.is_empty() {
130→                        println!("Usage: load <file.lgo>");
131→                    } else if let Err(e) = self.load_file(arg, None) {
132→                        println!("Error: {}", e);
133→                    }
134→                }
135→                "reset" => {
136→                    self.emu.reset();
137→                    self.uart_printed = 0;
138→                    println!("CPU reset. PC = 0x{:06X}", self.emu.pc());
139→                }
140→                "t" | "trace" => self.cmd_trace(arg),
141→                "uart" => self.cmd_uart(arg),
142→                "led" => self.cmd_led(),
143→                "button" | "btn" => self.cmd_button(arg),
144→                "help" | "h" | "?" => self.cmd_help(),
145→                _ => println!("Unknown command: '{}'. Type 'help' for commands.", parts[0]),
146→            }
147→        }
148→    }
149→
150→    fn print_new_uart(&mut self) {
151→        let output = self.emu.get_uart_output();
152→        if output.len() > self.uart_printed {
153→            print!("{}", &output[self.uart_printed..]);
154→            io::stdout().flush().ok();
155→            self.uart_printed = output.len();
156→        }
157→    }
158→
159→    fn cmd_run(&mut self, arg: &str) {
160→        if self.emu.is_halted() {
161→            println!("CPU is halted. Use 'reset' to restart.");
162→            return;
163→        }
164→
165→        let max: u64 = if arg.is_empty() {
166→            100_000_000
167→        } else {
168→            arg.replace('_', "").parse().unwrap_or(100_000_000)
169→        };
170→
171→        self.emu.resume();
172→        let result = self.emu.run_batch(max);
173→        self.print_new_uart();
174→
175→        match result.reason {
176→            StopReason::Halted => {
177→                println!(
178→                    "\nCPU halted after {} instructions",
179→                    result.instructions_run
180→                );
181→                self.cmd_trace("10");
182→            }
183→            StopReason::Breakpoint(addr) => {
184→                println!("Breakpoint at 0x{:06X}", addr);
185→            }
186→            StopReason::InvalidInstruction(byte) => {
187→                println!(
188→                    "\nInvalid instruction 0x{:02X} after {} instructions",
189→                    byte, result.instructions_run
190→                );
191→            }
192→            StopReason::CycleLimit => {
193→                println!(
194→                    "\nStopped after {} instructions (limit). PC = 0x{:06X}",
195→                    result.instructions_run,
196→                    self.emu.pc()
197→                );
198→            }
199→            StopReason::Paused => {}
200→        }

  1→//! COR24 assembler
  2→//!
  3→//! Parses COR24 assembly language and produces machine code.
  4→//! Uses encoding tables extracted from the hardware decode ROM.
  5→
  6→use crate::cpu::encode;
  7→use crate::cpu::instruction::Opcode;
  8→use serde::{Deserialize, Serialize};
  9→use std::collections::HashMap;
 10→
 11→/// Assembly result
 12→#[derive(Debug, Clone, Serialize, Deserialize)]
 13→pub struct AssemblyResult {
 14→    pub bytes: Vec<u8>,
 15→    pub lines: Vec<AssembledLine>,
 16→    pub errors: Vec<String>,
 17→    pub labels: HashMap<String, u32>,
 18→}
 19→
 20→/// A single assembled line
 21→#[derive(Debug, Clone, Serialize, Deserialize)]
 22→pub struct AssembledLine {
 23→    pub address: u32,
 24→    pub bytes: Vec<u8>,
 25→    pub source: String,
 26→    pub label: Option<String>,
 27→}
 28→
 29→/// COR24 Assembler
 30→pub struct Assembler {
 31→    /// Current address
 32→    address: u32,
 33→    /// Symbol table
 34→    labels: HashMap<String, u32>,
 35→    /// Forward references to resolve
 36→    forward_refs: Vec<ForwardRef>,
 37→    /// Output bytes
 38→    output: Vec<u8>,
 39→    /// Assembled lines
 40→    lines: Vec<AssembledLine>,
 41→    /// Errors
 42→    errors: Vec<String>,
 43→}
 44→
 45→#[derive(Debug, Clone)]
 46→struct ForwardRef {
 47→    address: u32,
 48→    label: String,
 49→    ref_type: RefType,
 50→    line_num: usize,
 51→}
 52→
 53→#[derive(Debug, Clone, Copy)]
 54→enum RefType {
 55→    Absolute24, // la instruction
 56→    Relative8,  // branch instruction
 57→}
 58→
 59→impl Default for Assembler {
 60→    fn default() -> Self {
 61→        Self::new()
 62→    }
 63→}
 64→
 65→impl Assembler {
 66→    pub fn new() -> Self {
 67→        Self {
 68→            address: 0,
 69→            labels: HashMap::new(),
 70→            forward_refs: Vec::new(),
 71→            output: Vec::new(),
 72→            lines: Vec::new(),
 73→            errors: Vec::new(),
 74→        }
 75→    }
 76→
 77→    /// Assemble source code
 78→    pub fn assemble(&mut self, source: &str) -> AssemblyResult {
 79→        self.address = 0;
 80→        self.labels.clear();
 81→        self.forward_refs.clear();
 82→        self.output.clear();
 83→        self.lines.clear();
 84→        self.errors.clear();
 85→
 86→        // First pass: collect labels and emit code
 87→        for (line_num, line) in source.lines().enumerate() {
 88→            self.assemble_line(line, line_num);
 89→        }
 90→
 91→        // Second pass: resolve forward references
 92→        self.resolve_forward_refs();
 93→
 94→        // Update line bytes from resolved output
 95→        for line in &mut self.lines {
 96→            if !line.bytes.is_empty() {
 97→                let addr = line.address as usize;
 98→                let len = line.bytes.len();
 99→                if addr + len <= self.output.len() {
100→                    line.bytes = self.output[addr..addr + len].to_vec();
101→                }
102→            }
103→        }
104→
105→        AssemblyResult {
106→            bytes: self.output.clone(),
107→            lines: self.lines.clone(),
108→            errors: self.errors.clone(),
109→            labels: self.labels.clone(),
110→        }
111→    }
112→
113→    fn assemble_line(&mut self, line: &str, line_num: usize) {
114→        let line = line.trim();
115→
116→        // Skip empty lines and comments
117→        if line.is_empty() || line.starts_with(';') {
118→            return;
119→        }
120→
121→        // Strip trailing comments (semicolon only, matching reference as24)
122→        let line = if let Some(pos) = line.find(';') {
123→            line[..pos].trim()
124→        } else {
125→            line
126→        };
127→
128→        if line.is_empty() {
129→            return;
130→        }
131→
132→        let start_addr = self.address;
133→        let mut label = None;
134→        let mut instruction_part = line;
135→
136→        // Check for label (must be on its own line, matching reference as24)
137→        if let Some(colon_pos) = line.find(':') {
138→            let label_str = line[..colon_pos].trim();
139→            if !label_str.is_empty() {
140→                label = Some(label_str.to_string());
141→                self.labels.insert(label_str.to_string(), self.address);
142→            }
143→            instruction_part = line[colon_pos + 1..].trim();
144→            if !instruction_part.is_empty() {
145→                self.errors.push(format!(
146→                    "Line {}: label must be on its own line (as24 compatible)",
147→                    line_num + 1
148→                ));
149→                return;
150→            }

  1→//! EmulatorCore: shared emulator controller for CLI and Web UI
  2→//!
  3→//! Provides run_batch(), pause/resume, breakpoints, and I/O accessors.
  4→//! Both the CLI debugger and Yew/WASM UI call this directly (no IPC).
  5→
  6→use crate::cpu::executor::{ExecuteResult, Executor};
  7→use crate::cpu::instruction::{DecodedInstruction, Opcode};
  8→use crate::cpu::state::{CpuState, DecodeRom};
  9→use crate::loader;
 10→
 11→/// Why a batch stopped
 12→#[derive(Debug, Clone, PartialEq, Eq)]
 13→pub enum StopReason {
 14→    /// Ran the requested number of instructions
 15→    CycleLimit,
 16→    /// Hit a breakpoint at this address
 17→    Breakpoint(u32),
 18→    /// CPU halted (executed halt sentinel)
 19→    Halted,
 20→    /// Invalid instruction encountered
 21→    InvalidInstruction(u8),
 22→    /// Emulator is paused (pause was requested)
 23→    Paused,
 24→}
 25→
 26→/// Result of a run_batch call
 27→#[derive(Debug, Clone)]
 28→pub struct BatchResult {
 29→    /// Number of instructions executed in this batch
 30→    pub instructions_run: u64,
 31→    /// Why execution stopped
 32→    pub reason: StopReason,
 33→    /// Number of new UART output bytes since batch started
 34→    pub uart_bytes_added: usize,
 35→    /// Whether LED state changed during batch
 36→    pub led_changed: bool,
 37→}
 38→
 39→/// Snapshot of CPU state for UI display
 40→#[derive(Debug, Clone)]
 41→pub struct CpuSnapshot {
 42→    pub regs: [u32; 8],
 43→    pub pc: u32,
 44→    pub c: bool,
 45→    pub halted: bool,
 46→    pub intis: bool,
 47→    pub cycles: u64,
 48→    pub instructions: u64,
 49→    pub led: u8,
 50→    pub button: u8,
 51→    pub uart_output_len: usize,
 52→}
 53→
 54→/// The shared emulator core
 55→#[derive(Clone)]
 56→pub struct EmulatorCore {
 57→    cpu: CpuState,
 58→    executor: Executor,
 59→    decode_rom: DecodeRom,
 60→    breakpoints: Vec<u32>,
 61→    paused: bool,
 62→    /// Highest address written during load (tracks end of code+data)
 63→    program_end: u32,
 64→}
 65→
 66→impl Default for EmulatorCore {
 67→    fn default() -> Self {
 68→        Self::new()
 69→    }
 70→}
 71→
 72→impl EmulatorCore {
 73→    pub fn new() -> Self {
 74→        Self {
 75→            cpu: CpuState::new(),
 76→            executor: Executor::new(),
 77→            decode_rom: DecodeRom::new(),
 78→            breakpoints: Vec::new(),
 79→            paused: true, // start paused
 80→            program_end: 0,
 81→        }
 82→    }
 83→
 84→    // ===== Load =====
 85→
 86→    /// Load an LGO file into memory, set entry point
 87→    pub fn load_lgo(&mut self, content: &str, entry: Option<u32>) -> Result<usize, String> {
 88→        self.cpu = CpuState::new();
 89→        let result = loader::load_lgo(content, &mut self.cpu)?;
 90→        let start = entry.or(result.start_addr).unwrap_or(0);
 91→        self.cpu.pc = start;
 92→        self.paused = true;
 93→        self.program_end = result.highest_address;
 94→        Ok(result.bytes_loaded)
 95→    }
 96→
 97→    /// Load assembled bytes into memory at given address
 98→    pub fn load_program(&mut self, addr: u32, bytes: &[u8]) {
 99→        self.cpu.load_program(addr, bytes);
100→        let end = addr + bytes.len() as u32;
101→        if end > self.program_end {
102→            self.program_end = end;
103→        }
104→    }
105→
106→    /// Set the program extent (highest address used by program code)
107→    pub fn load_program_extent(&mut self, end: u32) {
108→        if end > self.program_end {
109→            self.program_end = end;
110→        }
111→    }
112→
113→    /// Reset CPU (preserves memory)
114→    pub fn reset(&mut self) {
115→        self.cpu.reset();
116→        self.paused = true;
117→    }
118→
119→    /// Hard reset (clears memory too)
120→    pub fn hard_reset(&mut self) {
121→        self.cpu.hard_reset();
122→        self.paused = true;
123→    }
124→
125→    // ===== Run control =====
126→
127→    /// Run a batch of instructions. Returns what happened.
128→    pub fn run_batch(&mut self, max_instructions: u64) -> BatchResult {
129→        let uart_before = self.cpu.io.uart_output.len();
130→        let led_before = self.cpu.io.leds;
131→        let mut count = 0u64;
132→
133→        if self.cpu.halted {
134→            return BatchResult {
135→                instructions_run: 0,
136→                reason: StopReason::Halted,
137→                uart_bytes_added: 0,
138→                led_changed: false,
139→            };
140→        }
141→
142→        if self.paused {
143→            return BatchResult {
144→                instructions_run: 0,
145→                reason: StopReason::Paused,
146→                uart_bytes_added: 0,
147→                led_changed: false,
148→            };
149→        }
